func (f *CommandFactory) newMetricsSummaryCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "summary",
		Short: "Show a dashboard of process metrics",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			query, err := metricsQueryFromFlags(cmd)
			if err != nil {
				return err
