func (f *CommandFactory) newMetricsReworkCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "rework",
		Short: "Show reopen and revision facts",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			query, err := metricsQueryFromFlags(cmd)
			if err != nil {
