				len(report.Beads),
				len(report.Features),
				report.Summary.KnownCostUSD+report.Summary.EstimatedCostUSD,
			)
			for _, row := range report.Beads {
				if row.CostUSD == nil {
					fmt.Fprintf(cmd.OutOrStdout(), "%s  unknown\n", row.BeadID)
