				fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  %.3f  tokens=%d\n", row.BeadID, row.CostState, *row.CostUSD, row.TotalTokens)
			}
			return nil
		},
	}
	cmd.Flags().String("bead", "", "Limit to one bead")
	cmd.Flags().String("feature", "", "Limit to one spec-id")
